# Base module with abstract Shape class and interface

interface IDisplayable:
    def display_name(self) -> str: ...

@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

    @virtual
    def __str__(self) -> str:
        return f"Shape({self.name})"

    def display_name(self) -> str:
        return f"Displayable: {self.name}"

