# Utility module for shape operations

from base import Shape, IDisplayable
from shapes import Rectangle

class ShapeMetrics:
    area: float
    perimeter: float

    def __init__(self, area: float, perimeter: float):
        self.area = area
        self.perimeter = perimeter

    def __str__(self) -> str:
        return f"Metrics(area={self.area}, p={self.perimeter})"

def describe_shape(s: Shape) -> str:
    # Polymorphic dispatch - different __str__ for each shape
    return str(s)

def is_square(r: Rectangle) -> bool:
    return r.width == r.height

def create_metrics(shape: Shape) -> ShapeMetrics:
    return ShapeMetrics(shape.area(), shape.perimeter())

class ShapeCollection:
    shapes: list[Shape]

    def __init__(self):
        self.shapes = []

    def add(self, shape: Shape):
        self.shapes.append(shape)

    def total_area(self) -> float:
        total: float = 0.0
        for shape in self.shapes:
            total += shape.area()
        return total

    def total_perimeter(self) -> float:
        total: float = 0.0
        for shape in self.shapes:
            total += shape.perimeter()
        return total

    def __len__(self) -> int:
        return len(self.shapes)
